INSERT INTO `ai_messages` VALUES (7,4,14,'user','現在の都知事は。',8,NULL,'2025-10-15 18:51:03','2025-10-15 18:51:03'),(8,4,NULL,'assistant','小池百合子氏です。',9,NULL,'2025-10-15 18:51:03','2025-10-15 18:51:03'),(9,5,14,'user','彼女は何党の所属ですか。',12,NULL,'2025-10-15 18:51:15','2025-10-15 18:51:15'),(10,5,NULL,'assistant','申し訳ありませんが、その情報はわかりません。',22,NULL,'2025-10-15 18:51:15','2025-10-15 18:51:15'),(11,6,14,'user','小池百合子に関するウェブサイトを教えてください。',24,NULL,'2025-10-15 18:51:33','2025-10-15 18:51:33'),(12,6,NULL,'assistant','小池百合子に関するウェブサイトは、都知事公式サイト（https://www.yurikokoike.com/）があります。',61,NULL,'2025-10-15 18:51:34','2025-10-15 18:51:34'),(16,8,14,'user','あなたは誰ですか。',9,NULL,'2025-10-15 18:51:59','2025-10-15 18:51:59'),(17,8,14,'assistant','私はGoogleアシスタントです。どうぞお気軽に質問してください。',33,NULL,'2025-10-15 18:51:59','2025-10-15 18:51:59'),(18,8,14,'user','chatgptのエンジンはいくつですか。',20,NULL,'2025-10-15 18:51:59','2025-10-15 18:51:59'),(19,8,14,'assistant','ChatGPTのエンジンは3つです。',18,NULL,'2025-10-15 18:51:59','2025-10-15 18:51:59'),(20,8,14,'user','東京都の都庁所在地は何区ですか。',16,NULL,'2025-10-15 18:51:59','2025-10-15 18:51:59'),(21,8,14,'assistant','新宿区です。',6,NULL,'2025-10-15 18:51:59','2025-10-15 18:51:59'),(22,8,14,'user','現在の都知事は。',8,NULL,'2025-10-15 18:51:59','2025-10-15 18:51:59'),(23,8,14,'assistant','小池百合子氏です。',9,NULL,'2025-10-15 18:51:59','2025-10-15 18:51:59'),(24,8,14,'user','彼女は何党の所属ですか。',12,NULL,'2025-10-15 18:51:59','2025-10-15 18:51:59'),(25,8,14,'assistant','申し訳ありませんが、その情報はわかりません。',22,NULL,'2025-10-15 18:51:59','2025-10-15 18:51:59'),(26,8,14,'user','小池百合子に関するウェブサイトを教えてください。',24,NULL,'2025-10-15 18:51:59','2025-10-15 18:51:59'),(27,8,14,'assistant','小池百合子に関するウェブサイトは、都知事公式サイト（https://www.yurikokoike.com/）があります。',61,NULL,'2025-10-15 18:51:59','2025-10-15 18:51:59'),(28,8,14,'user','ファイルがアップされました\nsample.csv',24,'{\"file\": {\"url\": \"/storage/bot/sample.csv\", \"mime\": \"text/csv\", \"path\": \"bot/sample.csv\", \"size\": 268, \"original_name\": \"sample.csv\"}}','2025-10-15 18:51:59','2025-10-15 18:51:59'),(29,8,14,'user','このファイルを要約してください: sample.csv',27,NULL,'2025-10-15 18:52:04','2025-10-15 18:52:04'),(30,8,NULL,'system','File: sample.csv (summarized)',29,NULL,'2025-10-15 18:52:04','2025-10-15 18:52:04'),(31,8,NULL,'assistant','ファイル「sample.csv」には、山田太郎、佐藤花子、田中次郎の3人のユーザー情報が含まれています。それぞれの情報には名前、メールアドレス、パスワード、所属部署、役職、ユーザー権限が含まれています。',101,NULL,'2025-10-15 18:52:04','2025-10-15 18:52:04'),(88,7,1,'user','参照: sample.csv',14,NULL,'2025-10-18 23:19:44','2025-10-18 23:19:44'),(89,7,1,'system','File: sample.csv (summarized)',29,NULL,'2025-10-18 23:19:44','2025-10-18 23:19:44'),(90,7,1,'assistant','了解しました。サンプルCSVファイルを参照します。',25,NULL,'2025-10-18 23:19:44','2025-10-18 23:19:44'),(91,7,1,'user','ファイルがアップされました\nサンプル画像.png',24,'{\"file\": {\"url\": \"/storage/attachments/eb2c4aa7-d71d-4a99-80e1-fb0c53fc4fa0_サンプル画像.png\", \"mime\": \"image/png\", \"path\": \"attachments/eb2c4aa7-d71d-4a99-80e1-fb0c53fc4fa0_サンプル画像.png\", \"size\": 37347, \"original_name\": \"サンプル画像.png\"}}','2025-10-18 23:19:44','2025-10-18 23:19:44'),(92,7,1,'user','ファイルがアップされました\nサンプル画像 - コピー.png',30,'{\"file\": {\"url\": \"/storage/attachments/eb6d8a13-c580-4b19-af81-049edcc9a8a0_サンプル画像 - コピー.png\", \"mime\": \"image/png\", \"path\": \"attachments/eb6d8a13-c580-4b19-af81-049edcc9a8a0_サンプル画像 - コピー.png\", \"size\": 37347, \"original_name\": \"サンプル画像 - コピー.png\"}}','2025-10-18 23:19:44','2025-10-18 23:19:44'),(93,7,1,'user','ファイルがアップされました\nAIエージェント用プロンプト.txt',32,'{\"file\": {\"url\": \"/storage/attachments/19880020-9653-4f4c-bcb2-de7e1712e91d_AIエージェント用プロンプト.txt\", \"mime\": \"text/plain\", \"path\": \"attachments/19880020-9653-4f4c-bcb2-de7e1712e91d_AIエージェント用プロンプト.txt\", \"size\": 2294, \"original_name\": \"AIエージェント用プロンプト.txt\"}}','2025-10-18 23:19:44','2025-10-18 23:19:44'),(94,7,1,'user','ファイルがアップされました\nスクリーンショット 2025-07-15 091535.png',45,'{\"file\": {\"url\": \"/storage/attachments/1e1c28bb-bc1d-4729-aeb6-7b83543083f9_スクリーンショット 2025-07-15 091535.png\", \"mime\": \"image/png\", \"path\": \"attachments/1e1c28bb-bc1d-4729-ae